**Example:**
```typescript
// 1. Define an Interface (The "Contract")
interface HasBark {
  bark: () => void;
}

// 2. Create two completely different classes
class Dog {
  bark() { console.log("Woof"); }
}

class Robot {
  bark() { console.log("Beep Boop"); }
}

// 3. Use the Interface
function makeSound(animal: HasBark) {
  animal.bark();
}

// 4. Pass them in
makeSound(new Dog());   // ✅ Works
makeSound(new Robot()); // ✅ Works!

// Even a plain object works!
makeSound({ bark: () => console.log("Quack") }); // ✅ Works
```

